// Normalize incoming contact records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    contactId: String(j.contactId ?? j.id ?? '').trim(),
    email: typeof j.email === 'string' ? j.email.trim() : j.email ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;

// Score each contact 0-100 from simple heuristics
return $input.all().map(item => {
  const j = item.json;
  let score = 50;
  if (j.email) score += 20;
  if (j.company) score += 15;
  if ((j.source || '') === 'referral') score += 15;
  return { json: { ...j, score: Math.min(100, score) } };
});

// Round-robin owner assignment
const owners = ['ava@company.com', 'liam@company.com', 'mia@company.com'];
return $input.all().map((item, i) => ({
  json: { ...item.json, owner: owners[i % owners.length] },
}));
